import base64,gzip,os
BASE='/data/data/com.termux/files/home/rawagon/apps'
apps={
  "bitpawn": "",
  "droppa": "",
  "autoiq": "",
  "goldsnap": "",
  "qwks-protocol": "",
  "1nce-allcard": "",
  "rawagon-os": "",
  "profitpilot": ""
}
for name,enc in apps.items():
    os.makedirs(f'{BASE}/{name}',exist_ok=True)
    data=gzip.decompress(base64.b64decode(enc))
    with open(f'{BASE}/{name}/index.html','wb') as f:
        f.write(data)
    print(f'✓ {name} ({len(data)} bytes)')
print('All apps installed!')
